import{_ as a,c as i,o as s,ag as t}from"./chunks/framework.Co20b0ok.js";const l="/assets/image%2026.DRx3xGkj.png",o="/assets/image%2027.zwo5A0vz.png",r="/assets/image%2028.DFLRSDUa.png",p="/assets/image%2029.bmkB-7wz.png",u=JSON.parse('{"title":"SSRF & CSRF","description":"","frontmatter":{},"headers":[],"relativePath":"security/commonvuln/SSRF & CSRF.md","filePath":"security/commonvuln/SSRF & CSRF.md"}'),n={name:"security/commonvuln/SSRF & CSRF.md"};function c(h,e,d,k,S,m){return s(),i("div",null,e[0]||(e[0]=[t('<h1 id="ssrf-csrf" tabindex="-1">SSRF &amp; CSRF <a class="header-anchor" href="#ssrf-csrf" aria-label="Permalink to &quot;SSRF &amp; CSRF&quot;">​</a></h1><h2 id="csrf-跨站请求伪造" tabindex="-1">CSRF 跨站请求伪造 <a class="header-anchor" href="#csrf-跨站请求伪造" aria-label="Permalink to &quot;CSRF 跨站请求伪造&quot;">​</a></h2><p>Cross-site requestforgery 跨站请求伪造</p><p>XSS攻击是跨站脚本攻击，CSRF攻击是请求伪造</p><p><code>XSS</code>是实现<code>CSRF</code>的诸多途径中的一条，但并不是唯一的一条</p><blockquote><p><a href="https://blog.csdn.net/qq_43378996/article/details/123910614" target="_blank" rel="noreferrer">https://blog.csdn.net/qq_43378996/article/details/123910614</a></p></blockquote><h3 id="csrf-攻击条件" tabindex="-1">CSRF 攻击条件 <a class="header-anchor" href="#csrf-攻击条件" aria-label="Permalink to &quot;CSRF 攻击条件&quot;">​</a></h3><ol><li>目标用户已经登录了网站，能够执行网站的功能</li><li>目标用户访问了攻击者构造的<code>URL</code>（可以配合XSS）</li></ol><h3 id="黑盒判断csrf安全问题" tabindex="-1">黑盒判断CSRF安全问题 <a class="header-anchor" href="#黑盒判断csrf安全问题" aria-label="Permalink to &quot;黑盒判断CSRF安全问题&quot;">​</a></h3><ol><li>看验证来源是否要求 - referer</li><li>看凭据有无token</li><li>看关键操作有无验证</li></ol><h3 id="如何找-挖掘" tabindex="-1">如何找/挖掘 <a class="header-anchor" href="#如何找-挖掘" aria-label="Permalink to &quot;如何找/挖掘&quot;">​</a></h3><ol><li><p>直接复现看有没有</p><p>成功→有</p><p>失败→代码→缺陷过滤（绕过）→有</p><p>失败→代码→完全过滤→没有</p></li></ol><h3 id="复现-metinfo5-3-1-csrf" tabindex="-1">复现 - MetInfo5.3.1 CSRF <a class="header-anchor" href="#复现-metinfo5-3-1-csrf" aria-label="Permalink to &quot;复现 - MetInfo5.3.1 CSRF&quot;">​</a></h3><p>通过<code>csrf</code>跨站添加管理员，源代码网上可以找到</p><p>前提条件：</p><ul><li>被攻击者是登陆着管理后台的</li><li>知道被攻击网站使用的是什么CMS</li></ul><hr><ol><li><p>进入网站后台，查看仅有的用户（被攻击者视角）</p><p><img src="'+l+'" alt="image.png"></p></li><li><p>知道网站cms是MetInfo后我们到网上找源代码，然后本地搭建，抓取创建用户的数据包（攻击者视角）</p><p>使用<code>CSRFTester</code> ，一个用于构建CSRf数据包的工具</p><p>使用<code>CSRFTester</code> 抓取创建用户的数据包（在我们本地运行就行，只要是被攻击者是同一个cms）</p></li><li><p>随便输入数据（攻击者视角），<code>CSRFTester</code> 然后开始抓取，点击创建用户<code>yun</code>后，返回<code>CSRFTester</code> 查看抓到的数据包，很明</p></li><li><p>显的数据包，然后导出HTML（攻击者视角）</p><p><img src="'+o+'" alt="image.png"></p></li><li><p>修改导出的HTML数据包，这一部分就是修改数据的，<code>yun</code>应该是用户名，下面<code>123</code>应该就是密码，我们修改用户名为<code>hehe</code> ，密码为<code>123456</code> ，然后吧多余的<code>post</code>表单删掉，就留下我们创建用户的表单 ，IP地址可以改为<code>127.0.0.1</code> ,因为被攻击者的网站可能在本地（攻击者视角）</p><p><img src="'+r+'" alt="image.png"></p></li><li><p>构建完数据包后，我们构建一个XSS，点击后跳转到我们构建HTML地址，然后我们想方设法让被攻击者点击我们的XSS链接（攻击者视角）</p></li><li><p>被攻击者出于好奇点了我们的含有XSS攻击的链接，自动跳转到我们的构建好的创建用户的HTML，此时因为管理员后台是登陆状态的，所以直接提交HTML表单即可（被攻击者视角）</p><p>此时被攻击者点击了我们的链接</p><p>他的后台就会偷偷的出现了一个新的管理员账户</p><p><img src="'+p+'" alt="image.png"></p></li></ol><h2 id="ssrf-服务器请求伪造" tabindex="-1">SSRF 服务器请求伪造 <a class="header-anchor" href="#ssrf-服务器请求伪造" aria-label="Permalink to &quot;SSRF 服务器请求伪造&quot;">​</a></h2><blockquote><p><a href="https://www.cnblogs.com/miruier/p/13907150.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/miruier/p/13907150.html</a></p></blockquote><p>Server Side RequestForgery 服务器端请求伪造</p><p>SSRF 形成的原因大都是由于服务端提供了从其他服务器应用获取数据的功能且没有对目标地址做过滤与限制</p><p>可以通过SSRF进行探针攻击（扫描内网机器）</p><h3 id="可能出现漏洞的地方" tabindex="-1">可能出现漏洞的地方 <a class="header-anchor" href="#可能出现漏洞的地方" aria-label="Permalink to &quot;可能出现漏洞的地方&quot;">​</a></h3><ol><li><p>分享：通过URL地址分享网页内容</p><div class="language-jsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">share.renren.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">share</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">buttonshare.do</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">link</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//www.baidu.com@10.10.16.1</span></span></code></pre></div></li><li><p>在线翻译</p></li><li><p>图片、文章收藏功能</p><div class="language-jsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//title.xxx.com/title?title=http://title.xxx.com/as52ps63de</span></span></code></pre></div></li><li><p>图片加载与下载</p></li><li><p>从URL关键字中寻找</p><p><code>share,wap,url,link,src,source,target,u,display,sourceURl,imageURL,domain</code></p></li></ol><h3 id="产生漏洞的函数" tabindex="-1">产生漏洞的函数 <a class="header-anchor" href="#产生漏洞的函数" aria-label="Permalink to &quot;产生漏洞的函数&quot;">​</a></h3><blockquote><p><a href="https://blog.csdn.net/qq_43378996/article/details/124050308" target="_blank" rel="noreferrer">https://blog.csdn.net/qq_43378996/article/details/124050308</a></p></blockquote>',27)]))}const b=a(n,[["render",c]]);export{u as __pageData,b as default};
